export class NotAuthenticatedError extends Error {
    constructor(message) {
        super(message ??
            "Not authenticated. Run the login command to connect your Bitfab account.");
        this.name = "NotAuthenticatedError";
    }
}
export class StudioNavigationError extends Error {
    reason;
    blockedReason;
    staleSessionId;
    constructor(reason, blockedReason, staleSessionId) {
        super(blockedReason
            ? `Studio navigation failed (${reason}): ${blockedReason}`
            : `Studio navigation failed: ${reason}`);
        this.reason = reason;
        this.blockedReason = blockedReason;
        this.staleSessionId = staleSessionId;
        this.name = "StudioNavigationError";
    }
}
